const url = 'http://127.0.0.1:3000/api/space/%7BspaceId%7D/reward/claim';
const options = {
  method: 'POST',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN',
    'content-type': 'application/json'
  },
  body: '{"sourceType":"socialShare","sourceMetaData":{"platform":"x","postUrl":"string","postId":"string","snapshotId":"string","content":"string","username":"string","followerCount":0,"verifyResult":{"isValid":true,"errors":[{"message":"string","localization":{"i18nKey":"string","context":{"property1":null,"property2":null}}}]}}}'
};

try {
  const response = await fetch(url, options);
  const data = await response.json();
  console.log(data);
} catch (error) {
  console.error(error);
}

const http = require('http');

const options = {
  method: 'POST',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/space/%7BspaceId%7D/reward/claim',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN',
    'content-type': 'application/json'
  }
};

const req = http.request(options, function (res) {
  const chunks = [];

  res.on('data', function (chunk) {
    chunks.push(chunk);
  });

  res.on('end', function () {
    const body = Buffer.concat(chunks);
    console.log(body.toString());
  });
});

req.write(JSON.stringify({
  sourceType: 'socialShare',
  sourceMetaData: {
    platform: 'x',
    postUrl: 'string',
    postId: 'string',
    snapshotId: 'string',
    content: 'string',
    username: 'string',
    followerCount: 0,
    verifyResult: {
      isValid: true,
      errors: [
        {
          message: 'string',
          localization: {i18nKey: 'string', context: {property1: null, property2: null}}
        }
      ]
    }
  }
}));
req.end();

